cat > /tmp/binlog-reader/Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors
var errors = new List<(string Project, string Code, string File, int Line, string Message)>();

build.VisitAllChildren<Error>(error => {
    var project = "";
    var node = error.Parent;
    while (node != null) {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent as BaseNode;
    }
    errors.Add((project, error.Code ?? "", error.File ?? "", error.LineNumber, error.Text ?? error.ToString()));
});

// Collect all warnings too for context
var warnings = new List<(string Project, string Code, string Message)>();
build.VisitAllChildren<Warning>(warning => {
    var project = "";
    var node = warning.Parent;
    while (node != null) {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent as BaseNode;
    }
    warnings.Add((project, warning.Code ?? "", warning.Text ?? warning.ToString()));
});

Console.WriteLine("=== BUILD ERRORS ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

var byProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in byProject) {
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var err in group) {
        Console.WriteLine($"  [{err.Code}] {err.File}({err.Line}): {err.Message}");
    }
    Console.WriteLine();
}

// Check for MSB3202 (project reference not found) or similar cascading indicators
Console.WriteLine("=== POTENTIAL CASCADING FAILURES ===");
var cascading = errors.Where(e => e.Code == "MSB3202" || e.Code == "MSB4236" || e.Message.Contains("could not be found") && e.Code == "CS0246").ToList();
foreach (var c in cascading) {
    Console.WriteLine($"  [{c.Code}] in {c.Project}: {c.Message}");
}

Console.WriteLine();
Console.WriteLine("=== RELEVANT WARNINGS ===");
var relevantWarnings = warnings.Where(w => w.Code.StartsWith("MSB") || w.Code == "NU1603" || w.Code == "NU1605").Take(20).ToList();
foreach (var w in relevantWarnings) {
    Console.WriteLine($"  [{w.Code}] in {w.Project}: {w.Message}");
}
EOF
