cat > /tmp/binlog-reader/Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get project structure and references
Console.WriteLine("=== PROJECT STRUCTURE ===");
build.VisitAllChildren<Project>(project => {
    Console.WriteLine($"Project: {project.Name} (TargetFramework: {project.TargetFramework})");
});

Console.WriteLine();
Console.WriteLine("=== PACKAGE REFERENCES (from targets) ===");

// Look for package restore info
build.VisitAllChildren<Item>(item => {
    if (item.Name == "PackageReference" || item.Name == "_PackageReference") {
        TreeNode node = item.Parent;
        string proj = "";
        while (node != null) {
            if (node is Project p) { proj = p.Name; break; }
            node = node.Parent;
        }
        Console.WriteLine($"  {proj}: {item.Text}");
    }
});

Console.WriteLine();
Console.WriteLine("=== SOURCE FILE CONTENT (from items) ===");
build.VisitAllChildren<Message>(msg => {
    if (msg.Text != null && msg.Text.Contains("Newtonsoft")) {
        Console.WriteLine($"  MSG: {msg.Text.Substring(0, Math.Min(200, msg.Text.Length))}");
    }
});

// Look for restore/nuget issues
Console.WriteLine();
Console.WriteLine("=== ALL WARNINGS ===");
build.VisitAllChildren<Warning>(warning => {
    Console.WriteLine($"  [{warning.Code}] {warning.Text}");
});
EOF
