using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get detailed package references with metadata
Console.WriteLine("=== PACKAGE REFERENCES WITH DETAILS ===");
build.VisitAllChildren<AddItem>(item => {
    if (item.Name == "PackageReference") {
        TreeNode node = item.Parent;
        string proj = "";
        while (node != null) {
            if (node is Project p) { proj = p.Name; break; }
            node = node.Parent;
        }
        Console.WriteLine($"  {proj}: {item.Name}");
        foreach (var child in item.Children) {
            Console.WriteLine($"    -> {child}");
        }
    }
});

// Look for resolved references to understand what packages were restored
Console.WriteLine();
Console.WriteLine("=== RESOLVED REFERENCES IN SERVICES ===");
build.VisitAllChildren<AddItem>(item => {
    if (item.Name == "Reference" || item.Name == "ResolvedCompileFileDefinitions" || item.Name == "_ResolvedProjectReferencePaths") {
        TreeNode node = item.Parent;
        string proj = "";
        while (node != null) {
            if (node is Project p) { proj = p.Name; break; }
            node = node.Parent;
        }
        if (proj == "Services.csproj") {
            foreach (var child in item.Children) {
                var text = child.ToString();
                if (text.Contains("Newtonsoft") || text.Contains("Json")) {
                    Console.WriteLine($"  {item.Name}: {text}");
                }
            }
        }
    }
});

// Look at NuGet restore output
Console.WriteLine();
Console.WriteLine("=== NUGET RESTORE MESSAGES ===");
build.VisitAllChildren<Message>(msg => {
    if (msg.Text != null && (msg.Text.Contains("PackageReference") || msg.Text.Contains("Newtonsoft.Json")) && !msg.Text.Contains("Assembly loaded")) {
        TreeNode node = msg.Parent;
        string proj = "";
        while (node != null) {
            if (node is Project p) { proj = p.Name; break; }
            node = node.Parent;
        }
        Console.WriteLine($"  [{proj}] {msg.Text.Substring(0, Math.Min(300, msg.Text.Length))}");
    }
});

// Check project file content embedded in binlog
Console.WriteLine();
Console.WriteLine("=== EMBEDDED FILES (project files) ===");
var reader = new BinLogReader();
var records = reader.ReadRecords(binlogPath).ToList();
Console.WriteLine($"Total records: {records.Count}");

// Look for EmbeddedFiles
int embeddedCount = 0;
foreach (var record in records) {
    if (record.Args is Microsoft.Build.Framework.BuildMessageEventArgs msg2) {
        if (msg2.Message != null && msg2.Message.Contains(".csproj")) {
            // skip noisy ones
        }
    }
}
Console.WriteLine($"Embedded file count check done");
EOF
