using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Look for all Folder/NamedNode types under Services to find PackageReference items
Console.WriteLine("=== ITEMS ADDED IN SERVICES ===");
build.VisitAllChildren<Project>(proj => {
    if (proj.Name == "Services.csproj") {
        // Look at all children recursively for Item types
        proj.VisitAllChildren<Item>(item => {
            if (item.Text != null && (item.Text.Contains("Package") || item.Text.Contains("Newtonsoft") || item.Text.Contains("Json"))) {
                Console.WriteLine($"  Item: {item.Name} = {item.Text}");
            }
        });
        proj.VisitAllChildren<Metadata>(meta => {
            if (meta.ToString().Contains("Newtonsoft") || meta.ToString().Contains("Package")) {
                Console.WriteLine($"  Meta: {meta.Name} = {meta.Value}");
            }
        });
        // Show the target that does compilation and its references
        proj.VisitAllChildren<Parameter>(param => {
            if (param.Name == "References" || param.Name == "PackageReferences") {
                Console.WriteLine($"  Param: {param.Name}");
                foreach (var child in param.Children.Take(30)) {
                    var t = child.ToString();
                    if (t.Contains("Json") || t.Contains("Newtonsoft"))
                        Console.WriteLine($"    -> {t}");
                }
            }
        });
    }
});

// Also check the raw source content via BinLogReader EmbeddedFiles
Console.WriteLine();
Console.WriteLine("=== RAW BINLOG EMBEDDED CONTENT ===");
var reader = new BinLogReader();
foreach (var record in reader.ReadRecords(binlogPath)) {
