using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Dump the full tree for one Services.csproj invocation, looking for items
Console.WriteLine("=== ALL NAMED NODES IN SERVICES ===");
bool found = false;
build.VisitAllChildren<Project>(proj => {
    if (proj.Name == "Services.csproj" && !found) {
        found = true;
        proj.VisitAllChildren<NamedNode>(nn => {
            var t = nn.ToString();
            if (t.Contains("Newtonsoft") || (nn.Name != null && nn.Name == "PackageReference")) {
                Console.WriteLine($"  [{nn.GetType().Name}] {nn.Name}: {t.Substring(0, Math.Min(200, t.Length))}");
            }
        });
    }
});

// Try to extract .csproj files from the binlog archive
Console.WriteLine();
Console.WriteLine("=== EXTRACTING EMBEDDED FILES ===");
try {
    var archiveFiles = BinaryLog.ReadBuild(binlogPath).SourceFiles;
    if (archiveFiles != null) {
        Console.WriteLine($"Archive has {archiveFiles.Count} files");
        foreach (var kvp in archiveFiles) {
            Console.WriteLine($"  File: {kvp.Key}");
            if (kvp.Key.Contains(".csproj") || kvp.Key.Contains("UserService")) {
                Console.WriteLine($"--- CONTENT of {kvp.Key} ---");
                Console.WriteLine(kvp.Value.Substring(0, Math.Min(3000, kvp.Value.Length)));
                Console.WriteLine("--- END ---");
            }
        }
    } else {
        Console.WriteLine("No SourceFiles found in build");
    }
} catch (Exception ex) {
    Console.WriteLine($"Error: {ex.Message}");
}
