using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Reflection;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check ArchiveFile type
var sf = build.SourceFiles;
if (sf != null && sf.Count > 0) {
    var first = sf[0];
    var type = first.GetType();
    Console.WriteLine($"ArchiveFile type: {type.FullName}");
    foreach (var prop in type.GetProperties()) {
        Console.WriteLine($"  Property: {prop.Name} ({prop.PropertyType.Name})");
    }
    Console.WriteLine();

    // Now list all files
    foreach (var af in sf) {
        var nameP = type.GetProperty("FullPath") ?? type.GetProperty("Name") ?? type.GetProperty("FilePath");
        var name = nameP?.GetValue(af)?.ToString() ?? af.ToString();
        Console.WriteLine($"  File: {name}");
    }
}
