// Check build result per project
Console.WriteLine("=== BUILD RESULTS ===");
build.VisitAllChildren<Project>(proj => {
    if (proj.Children.OfType<Target>().Any()) {
        var succeeded = proj.FindChild<Target>("CoreCompile") != null;
        Console.WriteLine($"  {proj.Name} - Succeeded: {proj.Succeeded}");
    }
});

// Check if Api failed due to Services failure (cascading)
